+#[test]
+fn res_mkquery_null_returns_error() {
+    // res_mkquery with null dname should return -1 (via __res_mkquery GCT)
+    let r = unsafe {
+        res_mkquery(
+            0,
+            ptr::null(),
+            1, // C_IN
+            1, // T_A
+            ptr::null(),
+            0,
+            ptr::null(),
+            ptr::null_mut(),
+            0,
+        )
+    };
+    assert!(r <= 0);
+}
+
+#[test]
